  ('pukao-77f8735d-moex-00122', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '下列法規之修訂，何者曾特別引進「善良的撒瑪利亞人法」（Good Samaritan law）精神，以免除 相關行為人之法律責任，避免糾紛？', '["安寧緩和醫療條例", "醫師法", "醫療法", "緊急醫療救護法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00123', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '我國實施醫藥分業制度，下列敘述何者錯誤？', '["法源依據為藥物藥商管理法第102條", "於1997年3月1日開始實施", "原則是希望「醫師處方而不調劑、藥師調劑而不處方」", "主要規範限制基層診所醫師之調劑權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00124', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '民眾若有因預防接種而致死亡、身心障礙或嚴重疾病等傷害時，可申請傷害救濟。有關傷害救濟 制度之敘述，下列何者正確？', '["可申請藥害救濟，及時獲得受害救濟", "受害救濟主責機關為衛生福利部食品藥物管理署", "可向接種地所屬衛生局申請", "基金來源為藥害救濟基金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00125', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '衛生福利部中央健康保險署自2018年起鼓勵發展如「雁行計畫、共好聯盟」等健康照護模式，主 要係為醫療體系發揮何種功能？', '["高齡友善、優質長照", "資源均衡、健康平等", "分級醫療、雙向轉診", "衛福守護、婦幼健康"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00126', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '衛生福利部所屬機關職掌之規劃，多以業務功能導向來設計，唯有下列何機關係以服務對象或群 體為區分？', '["國民健康署", "疾病管制署", "食品藥物管理署", "社會及家庭署"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00127', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '2002年9月起，全民健康保險重大傷病範圍納入公告的罕見疾病，病人可免健保部分負擔。但全 民健康保險法未能給付之罕見疾病診斷、治療、藥物費用，則依據罕見疾病防治及藥物法第33條 規定，由衛生福利部所屬下列何者編列預算補助？', '["食品藥物管理署", "國民健康署", "護理及健康照護司", "長期照顧司"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00128', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '下列為五項我國重要之衛生政策或事件，請依據實際發生時間之先後順序排列，選出正確之選項：', '["醫療保健計畫-籌建醫療網計畫", "WHO宣布臺灣為瘧疾根除區", "牙醫醫療總額制度", "臺 灣成為高齡化（ageing）社會  ⑤長期照顧十年計畫（長照1.0）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL),
  ('pukao-77f8735d-moex-00129', 'pukao-77f8735d', 'pukao-77f8735d-moex-111-85716566', 'sub-pukao-77f8735d-03', NULL, 'single_choice', '毒品濫用是重要公共衛生議題，目前在監毒品受刑人員占全體在監受刑人比約：', '["5%", "10%", "25%", "45%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:05+00:00", "source_pdf_sha1": "dafabe2ce72c", "answer_pdf_sha1": "c17db9be48e8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "426", "s": "2102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生行政學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "衛生行政"}'::jsonb, NULL)
